@page "/chat"
@using sv_a90916013cd34132b07654c916867bef.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ───── Left sidebar: channel list ───── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-description">@Truncate(channel.Description, 40)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ───── Main message area ───── *@
    <main class="message-area @(threadOpen ? "" : "expanded")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <span class="channel-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <strong class="message-author">@msg.Author</strong>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var summary = threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (summary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" title="Add reaction"
                                            @onclick="() => ToggleEmojiPicker(msg.Id)">😊 React</button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option"
                                                        @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMessageKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </main>

    @* ───── Right panel: thread view ───── *@
    @if (threadOpen)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread">✕</button>
            </div>

            @if (threadRootMessage is not null)
            {
                <div class="thread-root-quote">
                    <strong>@threadRootMessage.Author</strong>
                    <span class="message-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                    <p>@threadRootMessage.Content</p>
                </div>
            }

            <div class="thread-messages">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-bubble">
                        <div class="message-meta">
                            <strong class="message-author">@reply.Author</strong>
                            <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="message-content">@reply.Content</div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<Message> threadReplies = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;

    private string newMessageText = "";
    private string threadReplyText = "";

    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool loadingMore;
    private bool allMessagesLoaded;

    private ElementReference messageListRef;

    private const int PageSize = 30;
    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🤔", "👀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messages.Clear();
        allMessagesLoaded = false;
        threadSummaries.Clear();
        emojiPickerMessageId = null;

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);
        RefreshChannelUnread(channel.Id);
    }

    private void RefreshChannelUnread(int channelId)
    {
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    // ── Pagination ──

    private async Task OnMessageListScroll()
    {
        // Scroll-to-top detection is approximated here; JS interop would be
        // needed for precise scroll-position checks. This handler fires on
        // every scroll event and loads more when not already loading.
        if (loadingMore || allMessagesLoaded || activeChannel is null)
            return;

        await LoadOlderMessagesAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (activeChannel is null) return;

        loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize)
            allMessagesLoaded = true;

        messages.InsertRange(0, older);
        BuildThreadSummaries();
        loadingMore = false;
    }

    // ── Send message ──

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Optimistic update
        var msg = messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = "";
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        threadReplyText = "";

        // Update thread summary in main list
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──

    private void BuildThreadSummaries()
    {
        // Build summaries from messages that are replies to other messages in this channel
        var replyGroups = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in replyGroups)
        {
            var replies = group.ToList();
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                replies.Count,
                replies.Max(r => r.SentAt));
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}

